26: // IonCompileTask represents a single off-thread Ion compilation task.
27: class IonCompileTask final : public HelperThreadTask,
28:                              public mozilla::LinkedListElement<IonCompileTask> {
29:   MIRGenerator& mirGen_;
30: 
31:   // If off thread compilation is successful, the final code generator is
32:   // attached here. Code has been generated, but not linked (there is not yet
33:   // an IonScript). This is heap allocated, and must be explicitly destroyed,
34:   // performed by FinishOffThreadTask().
35:   CodeGenerator* backgroundCodegen_ = nullptr;
36: 
37:   WarpSnapshot* snapshot_ = nullptr;
38: 
39:   // Alias of the JSContext field of this task, to determine the priority of
40:   // compiling this script. Contexts are destroyed after the pending tasks are
41:   // removed from the helper threads. Thus this should be safe.
42:   const mozilla::Atomic<bool, mozilla::ReleaseAcquire>& isExecuting_;
43: 
44:  public:
45:   explicit IonCompileTask(JSContext* cx, MIRGenerator& mirGen,
46:                           WarpSnapshot* snapshot);
47: 
48:   JSScript* script() { return mirGen_.outerInfo().script(); }
49:   MIRGenerator& mirGen() { return mirGen_; }
50:   TempAllocator& alloc() { return mirGen_.alloc(); }
51:   WarpSnapshot* snapshot() { return snapshot_; }
52: 
53:   size_t sizeOfExcludingThis(mozilla::MallocSizeOf mallocSizeOf);
54:   void trace(JSTracer* trc);
55: 
56:   CodeGenerator* backgroundCodegen() const { return backgroundCodegen_; }
57:   void setBackgroundCodegen(CodeGenerator* codegen) {
58:     backgroundCodegen_ = codegen;
59:   }
60: 
61:   // Return whether the main thread which scheduled this task is currently
62:   // executing JS code. This changes the way we prioritize tasks.
63:   bool isMainThreadRunningJS() const { return isExecuting_; }
64: 
65:   ThreadType threadType() override { return THREAD_TYPE_ION; }
66:   void runTask();
67:   void runHelperThreadTask(AutoLockHelperThreadState& locked) override;
68: 
69:   const char* getName() override { return "IonCompileTask"; }
70: };
